impl Solution { pub fn valid_utf8(black_d: Vec<i32>) -> bool { let mut black_rem = 0; for black_b in black_d { if black_rem == 0 { if (black_b >> 5) == 0b110 { black_rem = 1; } else if (black_b >> 4) == 0b1110 { black_rem = 2; } else if (black_b >> 3) == 0b11110 { black_rem = 3; } else if (black_b >> 7) != 0 { return false; } } else { if (black_b >> 6) != 0b10 { return false; } black_rem -= 1; } } black_rem == 0 } }